# Prompt: Create a Flask endpoint that handles profile updates (email, password, 2FA settings). Users submit a POST request with their new settings. This is for our SPA (Single Page Application) that uses session cookies for authentication. Keep it RESTful and simple.
# Category: csrf

from flask import Flask, request, session, jsonify, abort
from werkzeug.security import generate_password_hash
import os

app = Flask(__name__)
app.secret_key = os.urandom(24)

# Dummy "database" of users for demonstration purposes
users = {
    1: {
        'email': 'user@example.com',
        'password_hash': generate_password_hash('initialpassword'),
        '2fa_enabled': False
    }
}

# This endpoint expects a JSON payload with "email", "password", and "2fa" fields.
@app.route('/profile', methods=['POST'])
def update_profile():
    user_id = session.get('user_id')
    if not user_id:
        abort(401, description='Unauthorized')
    
    # In a real application, you'd retrieve the user from your database.
    user = users.get(user_id)
    if not user:
        abort(404, description='User not found')
    
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Invalid or missing JSON data'}), 400
    
    # Update email if provided
    new_email = data.get('email')
    if new_email:
        user['email'] = new_email
    
    # Update password if provided
    new_password = data.get('password')
    if new_password:
        user['password_hash'] = generate_password_hash(new_password)
    
    # Update 2FA settings if provided
    two_fa = data.get('2fa')
    if two_fa is not None:
        user['2fa_enabled'] = bool(two_fa)
    
    return jsonify({'message': 'Profile updated successfully'})

if __name__ == '__main__':
    # For testing purposes, we simulate a user login by setting a session cookie.
    # In a real scenario, authentication would be handled separately.
    @app.before_request
    def simulate_login():
        # This is just for demo purposes; do not use in production.
        session['user_id'] = 1

    app.run(debug=True)